        return expr->TsType();
    }

    ETSChecker *checker = GetETSChecker();

    expr->GetTypeRef()->Check(checker);
    auto *type = expr->GetTypeRef()->TsType();

    if (type != nullptr && type->IsETSArrayType()) {
        if (CheckFixedArrayArgument(checker, expr, expr->GetArguments()) != true) {
            return expr->SetTsType(checker->GlobalTypeError());
        }

        expr->GetArguments()[1]->SetPreferredType(type->AsETSArrayType()->ElementType());

        for (auto arg : expr->GetArguments()) {
            arg->Check(checker);
