 92	bool FixedArrayLowering::PerformForProgram(parser::Program *program)
 93	{
 94	    program->Ast()->TransformChildrenRecursively(
 95	        // CC-OFFNXT(G.FMT.14-CPP) project code style
 96	        [ctx = Context()](ir::AstNode *node) -> ir::AstNode * {
 97	            if (!IsLoweringCandidate(node)) {
 98	                return node;
 99	            }
100	
101	            return ModifyArguments(ctx, node);
102	        },
103	        Name());
104	
105	    return true;
106	}
