789	template <typename T, typename = typename std::enable_if_t<std::is_base_of_v<ir::Expression, T>>>
790	static bool CheckArrayElementType(ETSChecker *checker, T *newArrayInstanceExpr, checker::Type *elementType)
791	{
792	    ES2PANDA_ASSERT(checker != nullptr);
793	    ES2PANDA_ASSERT(newArrayInstanceExpr != nullptr);
794	    ES2PANDA_ASSERT(elementType != nullptr);
795	    ES2PANDA_ASSERT(!elementType->IsETSPrimitiveType());
796	
797	    if (elementType->IsETSObjectType()) {
798	        auto *calleeObj = elementType->AsETSObjectType();
799	        const auto flags = checker::ETSObjectFlags::ABSTRACT | checker::ETSObjectFlags::INTERFACE;
800	        if (calleeObj->HasObjectFlag(flags)) {
801	            checker->LogError(diagnostic::ABSTRACT_CLASS_AS_ARRAY_ELEMENT_TYPE, {}, newArrayInstanceExpr->Start());
802	            return false;
803	        }
804	    } else {
805	        if (!checker->Relation()->IsSupertypeOf(elementType, checker->GlobalETSUndefinedType()) &&
806	            !checker->Relation()->IsIdenticalTo(checker->GetApparentType(elementType), elementType)) {
807	            checker->LogError(diagnostic::TYPE_PARAMETER_AS_ARRAY_ELEMENT_TYPE, {}, newArrayInstanceExpr->Start());
808	            return false;
809	        }
810	        if (elementType->IsETSFunctionType() && newArrayInstanceExpr->IsETSNewClassInstanceExpression()) {
811	            return true;
812	        }
813	        if (!checker->Relation()->IsSupertypeOf(elementType, checker->GlobalETSUndefinedType())) {
814	            checker->LogError(diagnostic::NON_SUPERTYPE_OF_UNDEFINED_AS_ARRAY_ELEMENT_TYPE, {},
815	                              newArrayInstanceExpr->Start());
816	            return false;
817	        }
818	    }
819	    return true;
820	}
