822	static checker::Type *CheckInstantiatedNewType(ETSChecker *checker, ir::ETSNewClassInstanceExpression *expr)
823	{
824	    auto calleeType = expr->GetTypeRef()->Check(checker);
825	    FORWARD_TYPE_ERROR(checker, calleeType, expr->GetTypeRef());
826	
827	    if (calleeType->IsETSUnionType()) {
828	        return checker->TypeError(expr->GetTypeRef(), diagnostic::UNION_NONCONSTRUCTIBLE, expr->Start());
829	    }
830	    if (!ir::ETSNewClassInstanceExpression::TypeIsAllowedForInstantiation(calleeType)) {
831	        return checker->TypeError(expr->GetTypeRef(), diagnostic::CALLEE_NONCONSTRUCTIBLE, {calleeType}, expr->Start());
832	    }
833	    if (!calleeType->IsETSObjectType()) {
834	        return checker->TypeError(expr->GetTypeRef(), diagnostic::EXPR_NONCONSTRUCTIBLE, {}, expr->Start());
835	    }
836	
837	    auto calleeObj = calleeType->AsETSObjectType();
838	    if (calleeObj->HasObjectFlag(checker::ETSObjectFlags::ABSTRACT)) {
839	        checker->LogError(diagnostic::ABSTRACT_INSTANTIATION, {calleeObj->Name()}, expr->Start());
840	        return checker->GlobalTypeError();
841	    }
842	
843	    if (calleeObj->HasObjectFlag(checker::ETSObjectFlags::INTERFACE)) {
844	        checker->LogError(diagnostic::INTERFACE_INSTANTIATION, {calleeObj->Name()}, expr->Start());
845	        return checker->GlobalTypeError();
846	    }
847	
848	    if (calleeObj->HasObjectFlag(ETSObjectFlags::REQUIRED) &&
849	        !expr->HasAstNodeFlags(ir::AstNodeFlags::ALLOW_REQUIRED_INSTANTIATION)) {
850	        checker->LogError(diagnostic::NONLITERAL_INSTANTIATION, {}, expr->GetTypeRef()->Start());
851	        return checker->GlobalTypeError();
852	    }
853	
854	    return calleeType;
855	}
